package com.jonesys.vitalsy.ui.screen
import android.widget.Toast import androidx.compose.foundation.clickable import androidx.compose.foundation.layout.* import androidx.compose.foundation.shape.RoundedCornerShape import androidx.compose.foundation.text.ClickableText import androidx.compose.material3.* import androidx.compose.runtime.* import androidx.compose.ui.Alignment import androidx.compose.ui.Modifier import androidx.compose.ui.graphics.Color import androidx.compose.ui.platform.LocalContext import androidx.compose.ui.platform.testTag import androidx.compose.ui.text.SpanStyle import androidx.compose.ui.text.TextStyle import androidx.compose.ui.text.buildAnnotatedString import androidx.compose.ui.text.font.Font import androidx.compose.ui.text.font.FontFamily import androidx.compose.ui.text.font.FontWeight import androidx.compose.ui.text.input.PasswordVisualTransformation import androidx.compose.ui.text.style.TextAlign import androidx.compose.ui.text.withStyle import androidx.compose.ui.unit.dp import androidx.compose.ui.unit.sp import androidx.navigation.NavController import com.jonesys.vitalsy.ui.theme.CyberLime import com.jonesys.vitalsy.ui.theme.DeepBlack import com.jonesys.vitalsy.ui.theme.PureWhite import com.jonesys.vitalsy.ui.theme.SoftDarkGris import com.jonesys.vitalsy.viewmodel.LoginViewModel
// --- DEFINICIÓN DE FUENTES (Siguiendo tu patrón de Pacifico/Lato) --- // Asegúrate de que los archivos se llamen exactamente así en res/font
val SpaceGroteskBold = FontFamily(Font(R.font.space_grotesk_bold)) val SpaceGroteskMedium = FontFamily(Font(R.font.space_grotesk_medium))
val InterRegular = FontFamily(Font(R.font.inter_regular)) val InterSemiBold = FontFamily(Font(R.font.inter_semibold))
@OptIn(ExperimentalMaterial3Api::class) @Composable fun LoginScreen(viewModel: LoginViewModel, navController: NavController? = null) { val uiState by viewModel.formData.collectAsState() val contexto = LocalContext.current
LaunchedEffect(uiState.isLogin) { if (uiState.isLogin) { Toast.makeText(contexto, "Inicio de sesión exitoso", Toast.LENGTH_LONG).show() } }
Scaffold( modifier = Modifier.fillMaxSize(), containerColor = DeepBlack ) { paddingValues -> Column( modifier = Modifier .fillMaxSize() .padding(paddingValues) .padding(horizontal = 32.dp), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center ) { // --- LOGOTIPO (SPACE GROTESK) --- Text( text = "VITALSY", color = CyberLime, fontFamily = SpaceGrotesk, fontSize = 46.sp, // Un poco más grande para impacto fontWeight = FontWeight.Bold, letterSpacing = 6.sp, // El espaciado "Cyber" de tu defensa textAlign = TextAlign.Center )
Text( text = "Intelligent Diabetes Management", color = PureWhite.copy(alpha = 0.4f), fontFamily = Inter, fontSize = 11.sp, fontWeight = FontWeight.Normal, letterSpacing = 1.5.sp, modifier = Modifier.padding(bottom = 56.dp) )
// --- FORMULARIO (INTER) --- Column( modifier = Modifier.fillMaxWidth(), verticalArrangement = Arrangement.spacedBy(18.dp) ) { val textFieldColors = OutlinedTextFieldDefaults.colors( focusedBorderColor = CyberLime, unfocusedBorderColor = PureWhite.copy(alpha = 0.15f), focusedLabelColor = CyberLime, unfocusedLabelColor = PureWhite.copy(alpha = 0.4f), focusedTextColor = PureWhite, unfocusedTextColor = PureWhite, focusedContainerColor = SoftDarkGris, unfocusedContainerColor = SoftDarkGris )
OutlinedTextField( value = uiState.email, onValueChange = { viewModel.actualizarEmail(it) }, label = { Text("Email", fontFamily = Inter) }, placeholder = { Text("ejemplo@vitalsy.com", color = PureWhite.copy(alpha = 0.2f)) }, singleLine = true, modifier = Modifier.fillMaxWidth(), shape = RoundedCornerShape(16.dp), colors = textFieldColors, textStyle = TextStyle(fontFamily = Inter, fontSize = 16.sp) )
OutlinedTextField( value = uiState.password, onValueChange = { viewModel.actualizarPassword(it) }, label = { Text("Contraseña", fontFamily = Inter) }, visualTransformation = PasswordVisualTransformation(), singleLine = true, modifier = Modifier.fillMaxWidth(), shape = RoundedCornerShape(16.dp), colors = textFieldColors, textStyle = TextStyle(fontFamily = Inter, fontSize = 16.sp) ) }
// Gestión de Errores uiState.error?.let { Text( text = it, color = Color(0xFFFF5630), // El rojo de alerta que definimos fontSize = 12.sp, fontFamily = Inter, modifier = Modifier.padding(top = 10.dp).fillMaxWidth(), textAlign = TextAlign.Start ) }
Spacer(modifier = Modifier.height(36.dp))
// --- BOTÓN PRINCIPAL (SPACE GROTESK) --- Button( onClick = { viewModel.Login() }, modifier = Modifier .fillMaxWidth() .height(58.dp) .testTag("BTN_LOGIN"), shape = RoundedCornerShape(18.dp), colors = ButtonDefaults.buttonColors( containerColor = CyberLime, contentColor = DeepBlack ), elevation = ButtonDefaults.buttonElevation(defaultElevation = 0.dp) ) { Text( "INICIAR SESIÓN", fontFamily = SpaceGrotesk, fontSize = 15.sp, fontWeight = FontWeight.Bold, letterSpacing = 1.2.sp ) }
Spacer(modifier = Modifier.height(30.dp))
// --- FOOTER (INTER) --- val annotatedText = buildAnnotatedString { withStyle(style = SpanStyle(color = PureWhite.copy(alpha = 0.5f), fontFamily = Inter)) { append("¿Eres nuevo? ") } pushStringAnnotation(tag = "REGISTRO", annotation = "registro") withStyle(style = SpanStyle(color = CyberLime, fontWeight = FontWeight.Bold, fontFamily = Inter)) { append("Crea una cuenta") } pop() }
ClickableText( text = annotatedText, style = MaterialTheme.typography.bodyMedium.copy(textAlign = TextAlign.Center), onClick = { /* Navegar al Registro */ } )
Spacer(modifier = Modifier.height(48.dp))
Text( text = "Continuar como invitado", color = PureWhite.copy(alpha = 0.3f), fontFamily = Inter, fontSize = 13.sp, modifier = Modifier .clickable { /* Invitado */ } .padding(8.dp), textAlign = TextAlign.Center ) } } }

